// packages/database/src/db/schema/test-result.ts
// Drizzle table: testResult (generated by scripts/split-schema.ts)

import {
  pgTable,
  index,
  text,
  boolean,
  timestamp,
  integer,
  jsonb,
  type AnyPgColumn,
} from './_shared'
import { createId } from '@paralleldrive/cuid2'

import { TestRun } from './test-run'
import { TestCase } from './test-case'

/** Drizzle table for testResult */
export const TestResult = pgTable(
  'TestResult',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    runId: text()
      .notNull()
      .references((): AnyPgColumn => TestRun.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    testCaseId: text()
      .notNull()
      .references((): AnyPgColumn => TestCase.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    passed: boolean().notNull(),
    actualRules: jsonb().notNull(),
    actualActions: jsonb().notNull(),
    errorMessage: text(),
    executionTime: integer().notNull(),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
  },
  (table) => [
    index('TestResult_passed_idx').using('btree', table.passed.asc().nullsLast()),
    index('TestResult_runId_idx').using('btree', table.runId.asc().nullsLast()),
    index('TestResult_testCaseId_idx').using('btree', table.testCaseId.asc().nullsLast()),
  ]
)
